//! Write VHDL + SV + witness stub into `verifylog/` (paths relative to cwd).

use std::env;
use std::fs;
use std::path::PathBuf;

use gnosis_rtl_bridge::{
    emit_resolution_lift_sv, emit_resolution_lift_tb_vhdl, emit_resolution_lift_vhdl,
};

fn main() -> Result<(), String> {
    let mut out_vhdl = PathBuf::from("verifylog/vhdl");
    let mut out_witness = PathBuf::from("verifylog/witnesses");
    let mut args = env::args().skip(1);
    while let Some(a) = args.next() {
        if a == "--out" {
            let root = args.next().ok_or("--out needs a directory")?;
            out_vhdl = PathBuf::from(&root).join("vhdl");
            out_witness = PathBuf::from(&root).join("witnesses");
        }
    }

    fs::create_dir_all(&out_vhdl).map_err(|e| e.to_string())?;
    fs::create_dir_all(&out_witness).map_err(|e| e.to_string())?;

    fs::write(
        out_vhdl.join("gnosis_resolution_lift_fsm_v0.vhd"),
        emit_resolution_lift_vhdl(),
    )
    .map_err(|e| e.to_string())?;
    fs::write(
        out_vhdl.join("gnosis_resolution_lift_tb_v0.vhd"),
        emit_resolution_lift_tb_vhdl(),
    )
    .map_err(|e| e.to_string())?;
    fs::write(
        out_vhdl.join("gnosis_resolution_lift_fsm_v0.sv"),
        emit_resolution_lift_sv(),
    )
    .map_err(|e| e.to_string())?;

    eprintln!(
        "gnosis-rtl-emit: wrote VHDL + SV under {}",
        out_vhdl.display()
    );
    Ok(())
}
